public class SafePathTraversalExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter the file name: ");
        String fileName = scanner.nextLine();

        // Restrict file access to a specific directory
        String baseDirectory = "/path/to/your/directory/";

        if (!fileName.startsWith(baseDirectory)) {
            System.out.println("Access denied. Invalid file path.");
            return;
        }

        File file = new File(fileName);

